package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.lang.ref.SoftReference;
import java.lang.reflect.Field;
import java.util.Deque;
import java.util.Iterator;

import org.eclipse.rdf4j.common.transaction.IsolationLevels;
import org.eclipse.rdf4j.model.Statement;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.AbstractMemoryOverflowModel;
import org.eclipse.rdf4j.model.impl.DynamicModel;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

public class LmdbStoreIsolationModelReuseTest {

	@AfterEach
	void clearDynamicModelPool() throws Exception {
		Deque<SoftReference<DynamicModel>> pool = dynamicModelPool();
		synchronized (pool) {
			pool.clear();
		}
	}

	@Test
	void readCommittedBatchLoadReusesDynamicModelAcrossCommits(@TempDir File dataDir) throws Exception {
		Deque<SoftReference<DynamicModel>> pool = dynamicModelPool();
		synchronized (pool) {
			pool.clear();
		}

		SailRepository repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc")));
		repository.init();

		try {
			try (SailRepositoryConnection connection = repository.getConnection()) {
				ValueFactory vf = connection.getValueFactory();
				Iterator<Statement> iterator = new Iterator<>() {

					private int index;

					@Override
					public boolean hasNext() {
						return index < 20_001;
					}

					@Override
					public Statement next() {
						return vf.createStatement(vf.createIRI("urn:s" + index++), vf.createIRI("urn:p"),
								vf.createLiteral("o"));
					}
				};

				while (iterator.hasNext()) {
					connection.begin(IsolationLevels.READ_COMMITTED);
					for (int i = 0; i < 10_000 && iterator.hasNext(); i++) {
						connection.add(iterator.next());
					}
					connection.commit();
				}

				assertThat(connection.hasStatement(null, null, null, true)).isTrue();
			}
		} finally {
			repository.shutDown();
		}

		LmdbTestUtil.deleteDir(dataDir);
		assertThat(livePooledDynamicModels()).isEqualTo(1);
	}

	@SuppressWarnings("unchecked")
	private static Deque<SoftReference<DynamicModel>> dynamicModelPool() throws Exception {
		Field poolField = AbstractMemoryOverflowModel.class.getDeclaredField("DYNAMIC_MODEL_POOL");
		poolField.setAccessible(true);
		return (Deque<SoftReference<DynamicModel>>) poolField.get(null);
	}

	private static int livePooledDynamicModels() throws Exception {
		int liveModels = 0;
		Deque<SoftReference<DynamicModel>> pool = dynamicModelPool();
		synchronized (pool) {
			for (SoftReference<DynamicModel> reference : pool) {
				if (reference.get() != null) {
					liveModels++;
				}
			}
		}
		return liveModels;
	}
}
